1469   ///   2. The successors of the guard have the same flow into/around the loop.
1470   /// If the compare instructions are identical, then the first successor of the
1471   /// guard must go to the same place (either the preheader of the loop or the
1472   /// NonLoopBlock). In other words, the first successor of both loops must
1473   /// both go into the loop (i.e., the preheader) or go around the loop (i.e.,
1474   /// the NonLoopBlock). The same must be true for the second successor.
1475   bool haveIdenticalGuards(const FusionCandidate &FC0,
1476                            const FusionCandidate &FC1) const {
1477     assert(FC0.GuardBranch && FC1.GuardBranch &&
1478            "Expecting FC0 and FC1 to be guarded loops.");
