1397   /// Determine if two fusion candidates are strictly adjacent in the CFG.
1398   ///
1399   /// This method will determine if there are additional basic blocks in the CFG
1400   /// between the exit of \p FC0 and the entry of \p FC1.
1401   /// If the two candidates are guarded loops, then it checks whether the
1402   /// exit block of the \p FC0 is the predecessor of the \p FC1 preheader. This
1403   /// implicitly ensures that the non-loop successor of the \p FC0 guard branch
1404   /// is the entry block of \p FC1. If not, then the loops are not adjacent. If
1405   /// the two candidates are not guarded loops, then it checks whether the exit
1406   /// block of \p FC0 is the preheader of \p FC1.
1407   /// Strictly means there is no predecessor for FC1 unless it is from FC0,
1408   /// i.e., FC0 dominates FC1.
1409   bool isStrictlyAdjacent(const FusionCandidate &FC0,
1410                           const FusionCandidate &FC1) const {
1411     // If the successor of the guard branch is FC1, then the loops are adjacent
1412     if (FC0.GuardBranch)
1413       return DT.dominates(FC0.getEntryBlock(), FC1.getEntryBlock()) &&
1414              FC0.ExitBlock->getSingleSuccessor() == FC1.getEntryBlock();
1415     else
1416       return FC0.ExitBlock == FC1.getEntryBlock();
