1463   /// Determine if two fusion candidates have identical guards
1464   ///
1465   /// This method will determine if two fusion candidates have the same guards.
1466   /// The guards are considered the same if:
1467   ///   1. The instructions to compute the condition used in the compare are
1468   ///      identical.
1469   ///   2. The successors of the guard have the same flow into/around the loop.
1470   /// If the compare instructions are identical, then the first successor of the
1471   /// guard must go to the same place (either the preheader of the loop or the
1472   /// NonLoopBlock). In other words, the first successor of both loops must
1473   /// both go into the loop (i.e., the preheader) or go around the loop (i.e.,
1474   /// the NonLoopBlock). The same must be true for the second successor.
1475   bool haveIdenticalGuards(const FusionCandidate &FC0,
1476                            const FusionCandidate &FC1) const {
1477     assert(FC0.GuardBranch && FC1.GuardBranch &&
1478            "Expecting FC0 and FC1 to be guarded loops.");
1479 
1480     if (auto FC0CmpInst =
1481             dyn_cast<Instruction>(FC0.GuardBranch->getCondition()))
1482       if (auto FC1CmpInst =
1483               dyn_cast<Instruction>(FC1.GuardBranch->getCondition()))
1484         if (!FC0CmpInst->isIdenticalTo(FC1CmpInst))
1485           return false;
1486 
1487     // The compare instructions are identical.
1488     // Now make sure the successor of the guards have the same flow into/around
1489     // the loop
1490     if (FC0.GuardBranch->getSuccessor(0) == FC0.Preheader)
1491       return (FC1.GuardBranch->getSuccessor(0) == FC1.Preheader);
1492     else
1493       return (FC1.GuardBranch->getSuccessor(1) == FC1.Preheader);
1494   }
